export const meta = {
  name: 'qa-semantic-search',
  description: 'Execute semantic search for QA workflow',
  phases: [{ title: 'SemanticSearch' }],
}

phase('SemanticSearch')
const result = await agent(
  `You are executing the semantic search step of a QA workflow for Nablarch 6 knowledge base.

Execute the workflow at: /home/tie303177/work/nabledge/work2/.claude/skills/nabledge-6/workflows/semantic-search.md

The query is:
"Nablarch 5からNablarch 6にバージョンアップするとき、Jakarta EE 10対応でアプリケーションに影響がある変更は何か？（目的: バージョンアップしたい）"

The knowledge base is located at: /home/tie303177/work/nabledge/work2/.claude/skills/nabledge-6/knowledge/

Follow the semantic-search.md workflow exactly. Return the selected_sections array as JSON, including file paths, section IDs, and relevance (high/partial).

Also report:
- selected_pages: list of pages selected with reason
- excluded_pages: list of pages excluded with reason  
- excluded_sections: list of sections excluded with reason

Return your response as JSON with this structure:
{
  "selected_pages": [{"path": "...", "reason": "..."}],
  "excluded_pages": [{"path": "...", "reason": "..."}],
  "selected_sections": [{"file": "...", "section_id": "...", "relevance": "high|partial", "reason": "..."}],
  "excluded_sections": [{"file": "...", "section_id": "...", "reason": "..."}]
}`,
  {
    label: 'semantic-search',
    phase: 'SemanticSearch',
    schema: {
      type: 'object',
      properties: {
        selected_pages: {
          type: 'array',
          items: {
            type: 'object',
            properties: {
              path: { type: 'string' },
              reason: { type: 'string' }
            },
            required: ['path', 'reason']
          }
        },
        excluded_pages: {
          type: 'array',
          items: {
            type: 'object',
            properties: {
              path: { type: 'string' },
              reason: { type: 'string' }
            },
            required: ['path', 'reason']
          }
        },
        selected_sections: {
          type: 'array',
          items: {
            type: 'object',
            properties: {
              file: { type: 'string' },
              section_id: { type: 'string' },
              relevance: { type: 'string', enum: ['high', 'partial'] },
              reason: { type: 'string' }
            },
            required: ['file', 'section_id', 'relevance', 'reason']
          }
        },
        excluded_sections: {
          type: 'array',
          items: {
            type: 'object',
            properties: {
              file: { type: 'string' },
              section_id: { type: 'string' },
              reason: { type: 'string' }
            },
            required: ['file', 'section_id', 'reason']
          }
        }
      },
      required: ['selected_pages', 'excluded_pages', 'selected_sections', 'excluded_sections']
    }
  }
)

return result
